patch:
--- linux-2.6/drivers/serial/pmac_zilog.c.orig	2009-03-23 18:59:41.000000000 +0300
+++ linux-2.6/drivers/serial/pmac_zilog.c	2009-03-23 22:27:22.000000000 +0300
@@ -1532,6 +1532,11 @@ no_dma:
 	 */
 	uap->port.iotype = UPIO_MEM;
 	uap->port.irq = irq_of_parse_and_map(np, 0);
+	if (uap->port.irq == NO_IRQ) {
+		printk(KERN_ERR "pmac_zilog: can't map interrupt for %s\n",
+				np->full_name);
+		return -ENODEV;
+	}
 	uap->port.uartclk = ZS_CLOCK;
 	uap->port.fifosize = 1;
 	uap->port.ops = &pmz_pops;
